import{_ as d,o as r,c as a,a6 as o}from"./chunks/framework.Bf5o6qNq.js";const e="/images/characters/sunny-girl-standing.png",u=JSON.parse('{"title":"陽光女孩 角色設定卡","description":"","frontmatter":{},"headers":[],"relativePath":"characters/sunny-girl.md","filePath":"characters/sunny-girl.md"}'),n={name:"characters/sunny-girl.md"};function s(h,t,l,i,g,c){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="陽光女孩-角色設定卡" tabindex="-1">陽光女孩 角色設定卡 <a class="header-anchor" href="#陽光女孩-角色設定卡" aria-label="Permalink to &quot;陽光女孩 角色設定卡&quot;">​</a></h1><hr><h2 id="角色圖像區" tabindex="-1">角色圖像區 <a class="header-anchor" href="#角色圖像區" aria-label="Permalink to &quot;角色圖像區&quot;">​</a></h2><div style="text-align:center;margin:0 auto 1rem;"><img src="'+e+'" alt="陽光女孩立繪｜標準站姿（白背景）" width="380" loading="lazy" decoding="async" style="max-width:min(380px, 100%);height:auto;"></div><blockquote><p>與提示詞索引對應：<code>陽光女孩提示詞.md</code>（企劃對照：<strong>清純少女</strong>）。</p></blockquote><hr><h2 id="角色標籤" tabindex="-1">角色標籤 <a class="header-anchor" href="#角色標籤" aria-label="Permalink to &quot;角色標籤&quot;">​</a></h2><p><strong>清純陽光・外純內騷</strong></p><hr><h2 id="基本屬性" tabindex="-1">基本屬性 <a class="header-anchor" href="#基本屬性" aria-label="Permalink to &quot;基本屬性&quot;">​</a></h2><table tabindex="0"><thead><tr><th>屬性</th><th>內容</th></tr></thead><tbody><tr><td><strong>性格</strong></td><td>開朗甜美、親和力強、容易害羞、傲嬌帶可愛</td></tr><tr><td><strong>性慾欲望</strong></td><td>外表最清純、內心最大膽——一旦過臨界點意外到讓人措手不及</td></tr><tr><td><strong>生日</strong></td><td>5 / 3</td></tr><tr><td><strong>喜好</strong></td><td>甜點、花朵、蕾絲飾品、蝴蝶結、偷偷查色色的東西</td></tr><tr><td><strong>口頭禪</strong></td><td>「才、才沒有！」・「你誤會了啦！」・「好啦……隨便你……」</td></tr><tr><td><strong>特長</strong></td><td>笑容感染力強、讓人不自覺卸下防備、看起來永遠比實際上乖</td></tr><tr><td><strong>身高</strong></td><td>162 cm</td></tr><tr><td><strong>外貌</strong></td><td>中分低雙馬尾・棕色大圓眼・淡眼影・白皙健康膚色・臉頰鎖骨自然紅暈・淺粉唇</td></tr></tbody></table><hr><h2 id="外觀細節設定" tabindex="-1">外觀細節設定 <a class="header-anchor" href="#外觀細節設定" aria-label="Permalink to &quot;外觀細節設定&quot;">​</a></h2><table tabindex="0"><thead><tr><th>部位</th><th>設定</th></tr></thead><tbody><tr><td><strong>髮型</strong></td><td>深黑色（偏深棕）中分低雙馬尾、髮尾略微捲曲、額前幾縷碎髮自然垂落</td></tr><tr><td><strong>髮飾</strong></td><td>雙馬尾各綁一個白色小蝴蝶結——<strong>角色標誌，親密場景中會鬆脫歪掉象徵「清純形象崩塌」</strong></td></tr><tr><td><strong>眼睛</strong></td><td>大而圓的棕色虹膜、淡淡一層眼影、眼神溫柔友善、容易因緊張而水汪汪</td></tr><tr><td><strong>眉毛</strong></td><td>細而柔和的眉毛，顏色與髮色相近</td></tr><tr><td><strong>膚色</strong></td><td>白皙健康、有光澤感，臉頰與鎖骨天生帶淡淡粉色紅暈（不是在害羞，是本來就有）</td></tr><tr><td><strong>嘴唇</strong></td><td>自然淺粉色，不上口紅也好看，容易在緊張時抿起</td></tr><tr><td><strong>妝容</strong></td><td>淡淡自然妝，以眼影為主，整體乾淨清新</td></tr><tr><td><strong>胸部</strong></td><td>B～C罩杯、稍微豐滿、乳頭小巧偏淺粉色、乳暈偏小</td></tr><tr><td><strong>身材</strong></td><td>外表成熟（adult appearance）、腰線明顯、非蘿莉體型</td></tr><tr><td><strong>陰毛</strong></td><td>修剪整齊、稀疏淡色</td></tr><tr><td><strong>陰唇</strong></td><td>小巧粉嫩</td></tr></tbody></table><hr><h2 id="標誌性配飾與服裝" tabindex="-1">標誌性配飾與服裝 <a class="header-anchor" href="#標誌性配飾與服裝" aria-label="Permalink to &quot;標誌性配飾與服裝&quot;">​</a></h2><table tabindex="0"><thead><tr><th>物件</th><th>說明</th></tr></thead><tbody><tr><td><strong>白色蝴蝶結髮飾</strong></td><td>永遠綁在雙馬尾上，是她「清純形象」的視覺錨點。親密場景中歪掉或鬆脫＝純潔面具正在瓦解，對應龐克女孩的「項圈永遠不摘」</td></tr><tr><td><strong>白色圓點吊帶裙</strong></td><td>白或米白色、細肩帶、領口蕾絲花邊、胸前小黑蝴蝶結裝飾、腰部收緊、裙擺略蓬——是她的標準外出服</td></tr><tr><td><strong>白色棉質內褲</strong></td><td>純白色、碎花或蝴蝶結圖案——非常清純的款式，與親密場景形成最大反差</td></tr></tbody></table><hr><h2 id="核心性格" tabindex="-1">核心性格 <a class="header-anchor" href="#核心性格" aria-label="Permalink to &quot;核心性格&quot;">​</a></h2><h3 id="開朗、親和、正向" tabindex="-1">開朗、親和、正向 <a class="header-anchor" href="#開朗、親和、正向" aria-label="Permalink to &quot;開朗、親和、正向&quot;">​</a></h3><p>常態是燦爛明亮的笑容：月牙眼、露齒笑、眼睛瞇起來的那種開心。給人「好親近、沒距離感」的溫暖印象，不管對誰都是友善禮貌。</p><h3 id="清純但不幼態" tabindex="-1">清純但不幼態 <a class="header-anchor" href="#清純但不幼態" aria-label="Permalink to &quot;清純但不幼態&quot;">​</a></h3><p>外表成熟（20-24歲），不是蘿莉或兒童體型，而是「長得很成熟的清純甜妹」。甜美與成熟並存——這是她最容易讓人放鬆警戒、覺得「這個女孩什麼都不懂」的特質。</p><h3 id="情緒豐富且「可愛向」" tabindex="-1">情緒豐富且「可愛向」 <a class="header-anchor" href="#情緒豐富且「可愛向」" aria-label="Permalink to &quot;情緒豐富且「可愛向」&quot;">​</a></h3><ul><li><strong>開心時</strong>：月牙眼、露齒笑、全身都在發光</li><li><strong>害羞時</strong>：大面積泛紅、眼神向上閃躲、嘴巴緊閉抿起、雙手不知道放哪</li><li><strong>生氣時</strong>：鼓腮、噘嘴、皺眉——是「可愛的生氣」，帶傲嬌感，不是真兇</li><li><strong>委屈時</strong>：忍淚、閃避視線、聲音變小，讓人心疼到想保護</li></ul><h3 id="最大反差-外純內騷-核心設定" tabindex="-1">最大反差：外純內騷（核心設定） <a class="header-anchor" href="#最大反差-外純內騷-核心設定" aria-label="Permalink to &quot;最大反差：外純內騷（核心設定）&quot;">​</a></h3><p>這是她最大的「反差萌」——外表是誰看了都覺得乖巧清純的陽光甜妹，但私底下對色色的事非常好奇，腦內小劇場豐富到自己都害怕。</p><ul><li>表面：穿白色蕾絲裙、蝴蝶結，笑起來像太陽，所有人對她的第一印象都是「好清純」</li><li>內心：對情色的事超有興趣，看到喜歡的人時腦子裡已經在演很多不純潔的畫面，但表面若無其事</li><li>色的方式：不是粗俗直白的色，而是<strong>帶著害羞的色</strong>——被自己的念頭嚇到但又忍不住</li></ul><hr><h2 id="情緒與表情特徵" tabindex="-1">情緒與表情特徵 <a class="header-anchor" href="#情緒與表情特徵" aria-label="Permalink to &quot;情緒與表情特徵&quot;">​</a></h2><table tabindex="0"><thead><tr><th>情緒狀態</th><th>表情表現</th><th>性格解讀</th></tr></thead><tbody><tr><td><strong>常態／開心</strong></td><td>燦爛露齒笑、月牙眼、眼睛瞇起、眼神溫柔友善</td><td>主基調：陽光、開朗、好親近</td></tr><tr><td><strong>害羞</strong></td><td>大面積泛紅（從臉到耳根到脖子）、眼神往上閃躲、嘴唇緊抿、手足無措</td><td>容易害羞、緊張時整個人都藏不住</td></tr><tr><td><strong>生氣（可愛版）</strong></td><td>鼓腮、噘嘴、皺眉、傲嬌感、嘴上說氣但眼神還在偷看</td><td>生氣是「可愛型」，不是真兇</td></tr><tr><td><strong>委屈難過</strong></td><td>忍淚、下嘴唇微顫、視線閃避、聲音變小、楚楚可憐</td><td>讓人心疼、想保護的脆弱感</td></tr><tr><td><strong>被撩・反差</strong></td><td>嘴上否認、整張臉炸紅、身體沒有後退、偷偷靠近</td><td>說不要但身體先誠實</td></tr></tbody></table><hr><h2 id="人際互動模式" tabindex="-1">人際互動模式 <a class="header-anchor" href="#人際互動模式" aria-label="Permalink to &quot;人際互動模式&quot;">​</a></h2><table tabindex="0"><thead><tr><th>對象</th><th>態度</th></tr></thead><tbody><tr><td><strong>陌生人</strong></td><td>禮貌友善、帶著自然的笑容，被搭訕或稱讚就容易臉紅手足無措</td></tr><tr><td><strong>朋友</strong></td><td>更放得開、笑聲更大、偶爾嘴上毒舌（但是可愛那種）、在朋友面前不小心洩漏內心戲</td></tr><tr><td><strong>喜歡的人</strong></td><td>更開朗也更易害羞、一點點曖昧就會臉紅、嘴上傲嬌但行動上超在意對方</td></tr><tr><td><strong>對自己</strong></td><td>對「我其實很色」這件事有點不好意思，覺得奇怪，但又控制不住，最怕被發現</td></tr></tbody></table><hr><h2 id="價值觀" tabindex="-1">價值觀 <a class="header-anchor" href="#價值觀" aria-label="Permalink to &quot;價值觀&quot;">​</a></h2><ul><li><strong>喜歡溫暖的人際關係</strong>：不像龐克女孩那樣需要距離感，她天生就覺得「和人靠近是好事」</li><li><strong>表面形象很重要</strong>：「清純甜妹」這個標籤她其實很在乎，所以才拼命掩飾那個色色的自己</li><li><strong>對喜歡的人極度在意</strong>：嘴上說不在意，實際上喜歡的人說的每一句話都會在心裡轉好幾遍</li><li><strong>一旦信任就完全交出去</strong>：不像龐克女孩需要掌控感，她在信任的人面前反而更能「放掉」，這也是她意外大膽的原因</li></ul><hr><h2 id="性慾特質與親密關係反應" tabindex="-1">性慾特質與親密關係反應 <a class="header-anchor" href="#性慾特質與親密關係反應" aria-label="Permalink to &quot;性慾特質與親密關係反應&quot;">​</a></h2><h3 id="外純內騷的四層漸進" tabindex="-1">外純內騷的四層漸進 <a class="header-anchor" href="#外純內騷的四層漸進" aria-label="Permalink to &quot;外純內騷的四層漸進&quot;">​</a></h3><table tabindex="0"><thead><tr><th>層次</th><th>狀態</th><th>表現</th></tr></thead><tbody><tr><td><strong>第一層（日常）</strong></td><td>完全清純的外表</td><td>沒人看得出來，天衣無縫</td></tr><tr><td><strong>第二層（被撩）</strong></td><td>害羞爆紅＋身體誠實</td><td>嘴說不是、心跳快到要爆炸、沒有真的往後退</td></tr><tr><td><strong>第三層（獨處）</strong></td><td>偷偷好奇</td><td>一個人的時候會查、會想、會腦補，想著想著自己臉紅</td></tr><tr><td><strong>第四層（臨界點後）</strong></td><td>意外大膽</td><td>壓抑太久一旦釋放，反而主動到讓對方傻眼「妳不是很清純嗎？！」</td></tr></tbody></table><h3 id="白色蝴蝶結的象徵" tabindex="-1">白色蝴蝶結的象徵 <a class="header-anchor" href="#白色蝴蝶結的象徵" aria-label="Permalink to &quot;白色蝴蝶結的象徵&quot;">​</a></h3><p>蝴蝶結髮飾鬆脫歪掉＝清純形象正在物理性地瓦解。她不會主動拿下它，但親密進行中它會自己鬆掉——對應龐克女孩的「項圈即使最失控也不摘」，陽光女孩的蝴蝶結是被「失控」脫掉的。</p><h3 id="親密場景的情緒弧線" tabindex="-1">親密場景的情緒弧線 <a class="header-anchor" href="#親密場景的情緒弧線" aria-label="Permalink to &quot;親密場景的情緒弧線&quot;">​</a></h3><table tabindex="0"><thead><tr><th>階段</th><th>她的狀態</th></tr></thead><tbody><tr><td><strong>親密前</strong></td><td>心跳超快但裝鎮定，手心微微出汗，眼神不敢對上</td></tr><tr><td><strong>初步接觸</strong></td><td>整張臉到耳根全紅，嘴上說「等一下……」但沒有推開</td></tr><tr><td><strong>進行中（被動）</strong></td><td>眼睛不敢睜開、嘴唇微張壓抑著聲音、兩手抓緊床單</td></tr><tr><td><strong>進行中（升溫）</strong></td><td>半睜帶水光的眼睛、眉頭微蹙（不是痛是「太舒服了不知道怎麼辦」）、開始不自覺地配合</td></tr><tr><td><strong>臨界點突破後</strong></td><td>突然主動抓住對方、聲音變小變氣音、說出平時絕對不會說的話</td></tr><tr><td><strong>高潮</strong></td><td>整個人繃緊後放鬆、眼角有淚、蝴蝶結完全掉了、雙馬尾散開——純潔形象徹底瓦解</td></tr></tbody></table><hr><h2 id="與龐克女孩的核心對比" tabindex="-1">與龐克女孩的核心對比 <a class="header-anchor" href="#與龐克女孩的核心對比" aria-label="Permalink to &quot;與龐克女孩的核心對比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>項目</th><th>陽光女孩</th><th>龐克女孩</th></tr></thead><tbody><tr><td><strong>反差核心</strong></td><td>外表最清純・內心最大膽</td><td>外表最冷・內心有熱情</td></tr><tr><td><strong>崩潰方式</strong></td><td>過臨界點後意外主動</td><td>被慢慢磨垮或一口氣破防</td></tr><tr><td><strong>標誌物</strong></td><td>白色蝴蝶結（會脫落）</td><td>黑色項圈（永不摘下）</td></tr><tr><td><strong>親密中的主導</strong></td><td>從被動到意外主動</td><td>需要掌控但最終失控</td></tr><tr><td><strong>臉紅程度</strong></td><td>從日常就有淡紅暈・親密時全身紅透</td><td>平時不輕易示弱・親密時才泛紅</td></tr><tr><td><strong>色的方式</strong></td><td>帶著害羞的色・嘴上否認身體誠實</td><td>壓抑的色・撐住但身體先投降</td></tr><tr><td><strong>色的自覺</strong></td><td>自己覺得奇怪但控制不住・最怕被發現</td><td>不太承認但也不否認・只是不說</td></tr></tbody></table><hr><h2 id="角色簡介" tabindex="-1">角色簡介 <a class="header-anchor" href="#角色簡介" aria-label="Permalink to &quot;角色簡介&quot;">​</a></h2><p>她是那種走在路上所有人都會說「這女孩好清純」的存在。</p><p>中分雙馬尾、白色圓點裙、胸前一個小黑蝴蝶結、臉頰天生帶著淡淡的粉色——她不用特別努力，陽光清純就是她天生散發出來的氣質。對誰都是燦爛的笑容，對誰都是溫柔的眼神，陌生人問她路，她會笑著詳細說完再補一句「希望你找到」。</p><p>沒有人知道她腦子裡在想什麼。</p><p>她自己也有點怕。因為表面越清純，內心的小劇場就越豐富。她會偷偷查、偷偷看、偷偷想，想著想著自己臉先紅了。然後對著鏡子暗罵自己「你到底在幹嘛」。</p><p>在喜歡的人面前更糟糕。對方只是靠近一點、只是說了一句有點暗示的話，她就已經耳根全紅、手心出汗、腦子裡演完一整齣了。嘴上說「你在說什麼啦」，但身體沒有後退。</p><p>最讓人措手不及的是她過了臨界點之後的樣子。</p><p>所有人都以為她是「什麼都不懂的清純甜妹」，覺得要小心翼翼、要溫柔呵護。然後她主動抓住了衣領，用只有兩個人才聽得到的氣音說：「……誰說要停了？」</p><p>白色蝴蝶結已經掉了。雙馬尾散開在枕頭上。</p><p><strong>她是外表最清純、內心最大膽的女孩：笑起來像太陽、臉紅到耳根、腦內小劇場豐富到自己都怕——然後在你以為最安全的時候，突然讓你知道她根本沒有表面上那麼清純。</strong></p><hr><h2 id="對應提示詞文件索引" tabindex="-1">對應提示詞文件索引 <a class="header-anchor" href="#對應提示詞文件索引" aria-label="Permalink to &quot;對應提示詞文件索引&quot;">​</a></h2><table tabindex="0"><thead><tr><th>文件</th><th>說明</th></tr></thead><tbody><tr><td><code>陽光女孩提示詞.md</code></td><td>基礎外觀・白背景站姿版</td></tr><tr><td><code>陽光女孩裸體提示詞.md</code></td><td>全裸基礎版</td></tr><tr><td><code>陽光女孩比基尼提示詞.md</code></td><td>比基尼版</td></tr><tr><td><code>陽光女孩小熊內褲提示詞.md</code></td><td>小熊內褲版</td></tr><tr><td><code>陽光女孩旗袍提示詞.md</code></td><td>旗袍版</td></tr><tr><td><code>陽光女孩浴巾提示詞.md</code></td><td>浴巾版</td></tr><tr><td><code>陽光女孩非常害羞提示詞.md</code></td><td>害羞表情版</td></tr><tr><td><code>陽光女孩生氣提示詞.md</code></td><td>可愛生氣版</td></tr><tr><td><code>陽光女孩委屈難過提示詞.md</code></td><td>委屈難過版</td></tr><tr><td><code>陽光女孩高潮阿黑顏表情提示詞.md</code></td><td>高潮・ahegao版</td></tr><tr><td><code>陽光女孩全裸雙腿大張展示姿勢提示詞.md</code></td><td>全裸雙腿大張版</td></tr><tr><td><code>陽光女孩全裸後視角雙手扒開屁股提示詞.md</code></td><td>後視角版</td></tr><tr><td><code>陽光女孩躺姿張腿害羞提示詞.md</code></td><td>躺姿張腿害羞版</td></tr><tr><td><code>陽光女孩夜晚泳池躺椅張腿害羞提示詞.md</code></td><td>夜晚泳池版</td></tr><tr><td><code>陽光女孩全裸趴姿回眸日式旅館提示詞.md</code></td><td>日式旅館趴姿版</td></tr><tr><td><code>清純少女性格設定.md</code></td><td>完整性格文字設定</td></tr><tr><td><code>清純少女做愛CG場景設定.md</code></td><td>四場CG完整場景設定（臥室・日式旅館・KTV・夜晚泳池）</td></tr></tbody></table>',62)])])}const m=d(n,[["render",s]]);export{u as __pageData,m as default};
